settings.custom_liquid:
{% comment %}
  Breadcrumbs Section for Dawn Theme
{% endcomment %}

{% if template != 'index' and template != 'cart' %}
<div class="breadcrumb-wrapper">  
  <nav class="breadcrumb" role="navigation" aria-label="breadcrumbs">
    <a href="{{ routes.root_url }}" class="">Home</a>

    {% if template contains 'collection' and collection %}
      <span class="mx-2"> > </span>
      <span>{{ collection.title }}</span>

    {% elsif template contains 'product' and product %}
      {% if product.collections.size > 0 %}
        {% for coll in product.collections %}
          <span class="mx-2"> > </span>
          <a href="{{ coll.url }}" class="">{{ coll.title }}</a>
        {% endfor %}
      {% endif %}
      <span class="mx-2"> > </span>
      <span>{{ product.title }}</span>

    {% elsif template contains 'article' and article %}
      <span class="mx-2"> > </span>
      <a href="{{ blog.url }}" class="">{{ blog.title }}</a>
      <span class="mx-2"> > </span>
      <span>{{ article.title }}</span>

    {% elsif template contains 'page' and page %}
      <span class="mx-2"> > </span>
      <span>{{ page.title }}</span>

    {% elsif template contains 'search' %}
      <span class="mx-2"> > </span>
      <span>Search</span>
    {% endif %}
  </nav>
<p class="product-sku">
  <strong>SKU:</strong> {{ product.selected_or_first_available_variant.sku }}
</p>
</div>
{% endif %}



<style>
  .breadcrumb {
    font-size: 0.9rem;
    padding: 10px 20px;
  }

  .section-template--19466783981784__custom_liquid_TMzBiR-padding {
    padding: 0 5rem;
    max-width: 1599px;
    margin: auto;
  }

  nav.breadcrumb {
    font-family: 'Poppins';
    font-size: 12px;
    font-weight: 400;
    color: #00514E;
  }

  nav.breadcrumb a {
    font-family: 'Poppins';
    font-size: 12px;
    font-weight: 400;
    color: #00514E;
    text-decoration: none;
  }
</style>
